import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider, Chip } from '@mui/material';
import response from './response.json';

interface NextToWatch {
  title: string;
  season: number;
  episode: number;
  progress: string;
}

interface WatchlistSummary {
  totalShows: number;
  episodesLeft: number;
  timeToFinish: string;
}

interface StreamingData {
  nextToWatch: NextToWatch;
  watchlistSummary: WatchlistSummary;
}

export default function Widget() {
  const streamingData = response.data as StreamingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1C1C1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FF3B30', mb: 1 }}>
              Next to Watch
            </Typography>
            <Typography variant="h5" fontWeight={700}>
              {streamingData.nextToWatch.title}
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              Season {streamingData.nextToWatch.season}, Episode {streamingData.nextToWatch.episode}
            </Typography>
            <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5, display: 'block' }}>
              Progress: {streamingData.nextToWatch.progress}
            </Typography>
          </Box>

          <Divider sx={{ borderColor: '#FF3B30' }} />

          <Box>
            <Typography variant="body2" sx={{ color: '#FF3B30', mb: 1 }}>
              Watchlist Summary
            </Typography>
            <Stack direction="row" spacing={1}>
              <Chip label={`Total Shows: ${streamingData.watchlistSummary.totalShows}`} sx={{ fontSize: '12px', bgcolor: '#333333', color: '#FFFFFF' }}/>
              <Chip label={`Episodes Left: ${streamingData.watchlistSummary.episodesLeft}`} sx={{ fontSize: '12px', bgcolor: '#333333', color: '#FFFFFF' }}/>
              <Chip label={`Time to Finish: ${streamingData.watchlistSummary.timeToFinish}`} sx={{ fontSize: '12px', bgcolor: '#333333', color: '#FFFFFF' }}/>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
